#include<bits/stdc++.h>
#define fst(a,b,c) for(int a=(b);a<=(c);a++)
#define est(x) for(int i=hd[x],y=to[i];i;i=nt[i],y=to[i])
#define Est(x) for(int y: nxt[x])
#define pii pair<int,int>
#define mp(x,y) make_pair(x,y)
#define fr first
#define sc second
using namespace std;
const int N=2e4+100,M=2e5+100,K=22;
int n,m,k,q,ans=1e9;

int id[K],ord[N],fa[K],p[21][20],res[21],f[2][185000][20];
vector<int> nxt[K];
int in[K]; bool use[1<<K];
vector<int> stu[20]; int loc[(1<<20)-1];

int hd[N],to[M*2],vl[M*2],nt[M*2],tot;
int dis[N];
priority_queue<pii,vector<pii >,greater<pii > > que;
bool vis[N];

int read(){
	char in=getchar(); int x=0;
	while(!isdigit(in)) in=getchar();
	while(isdigit(in)) x=x*10+(in^48),in=getchar();
	return x;
}
void add(int x,int y,int z){
	to[++tot]=y;vl[tot]=z;nt[tot]=hd[x];hd[x]=tot;
	to[++tot]=x;vl[tot]=z;nt[tot]=hd[y];hd[y]=tot;
}
void calc(int s){
	memset(dis,0x3f,sizeof(dis));
	memset(vis,0,sizeof(vis));
	que.push(mp(dis[s]=0,s));
	while(!que.empty()){
		int x=que.top().sc; que.pop();
		est(x){
			if(dis[y]>dis[x]+vl[i]){
				que.push(mp(dis[y]=dis[x]+vl[i],y));
			}
		}
	}
	fst(i,0,k-1) p[ord[s]][i]=dis[id[i]];
	res[ord[s]]=dis[n];
	return;
}
void build(int x){
	calc(id[x]);
	Est(x){
		fa[y]|=fa[x]|(1<<x);
		if(!(--in[y])) build(y);
	}
}
int main(){
	int x,y,z;
	memset(f,0x3f,sizeof(f));
//	freopen("journey.in","r",stdin);
//	freopen("journey.out","w",stdout);
	n=read(),m=read(),k=read();
	fst(i,0,(1<<k)-1) stu[__builtin_popcount(i)].push_back(i),loc[i]=(int)stu[__builtin_popcount(i)].size()-1;
	fst(i,1,m) x=read(),y=read(),z=read(),add(x,y,z);
	fst(i,2,k+1) id[i-2]=i,ord[i]=i-2; id[k]=1; ord[1]=k;
	q=read();
	fst(i,1,q){
		x=read(),y=read();
		nxt[ord[x]].push_back(ord[y]);
		in[ord[y]]++;
	}
	calc(1);
	fst(i,0,k-1) if(!in[i]) build(i),f[1][loc[1<<i]][i]=p[k][i];
	fst(c,1,k-1){
		memset(f[(c&1)^1],0x3f,sizeof(f[(c&1)^1]));
		fst(now,0,(int)stu[c].size()-1){
			int s=stu[c][now];
			fst(i,0,k-1){
				if(!((s>>i)&1)) continue;
				fst(j,0,k-1)
				{
					if(((s>>j)&1)||(fa[j]&s)!=fa[j]) continue;
					f[(c&1)^1][loc[s|(1<<j)]][j]=min(f[(c&1)^1][loc[s|(1<<j)]][j],f[c&1][now][i]+p[i][j]);
				}
				
			}
		}
	}
	fst(i,0,k-1) ans=min(ans,f[k&1][loc[(1<<k)-1]][i]+res[i]);
	printf("%d\n",ans);
	return 0;
}
